static double getElapsedtime(cudaEvent_t start, cudaEvent_t end) {
    float time_ms;
    CUDA_SAFE_CALL(cudaEventRecord(start));
    CUDA_SAFE_CALL(cudaEventRecord(end));
    CUDA_SAFE_CALL(cudaEventSynchronize(end));
    CUDA_SAFE_CALL(cudaEventElapsedTime(&time_ms, start, end));
    return time_ms;
}

template<int N, typename F>
double benchmark(F func) {
    double times[N];
    for(int i = 0; i < N; i++) {
        times[i] = func();
    }
    double min_time = times[0];
    for(int i = 1; i < N; i++) {
        if(times[i] < min_time) min_time = times[i];
    }
    return min_time;
}

void show_progress_init(int length) {
    printf("[");
    for (int i = 0; i < length; i++)
        printf(" ");
    printf("]");
    for (int i = 0; i <= length; i++)
        printf("\b");
}

void show_progress_step(int domove, char newchar) {
    printf("%c", newchar);
    if (!domove)
        printf("\b");
}

void show_progress_done(void) {
    printf("\n");
}

void runbench_warmup(dim3 block, dim3 grid, cudaKernel_t kernel, void** args, long size) {
    const long reduced_grid_size = size / 256;
    grid.x = reduced_grid_size / block.x;
    if(grid.x < 1) grid.x = 1;

    CUDA_SAFE_CALL(cudaLaunchKernel(kernel, grid, block, 0, 0, args));
    CUDA_SAFE_CALL(cudaDeviceSynchronize());
}

void runbench(const int compute_iterations[],
              unsigned int krn_idx,
              dim3 block,
              cudaKernel_t kernels[kdt_double + 1][compute_iterations_len],
              void** kernel_args,
              double* cbuffer,
              long size,
              unsigned int elements_per_wi,
              unsigned int fusion_degree) {
    const long compute_grid_size = size / elements_per_wi / fusion_degree;
    const int current_compute_iterations = compute_iterations[krn_idx];
    const long long computations =
        (elements_per_wi * (long long)compute_grid_size +
         (2 * elements_per_wi * current_compute_iterations) *
             (long long)compute_grid_size) *
        fusion_degree;
    const long long memoryoperations = size;

    dim3 grid;
    grid.x = compute_grid_size / block.x;
    if(grid.x < 1) grid.x = 1;
    grid.y = 1;
    grid.z = 1;

    constexpr auto total_bench_iterations = 3;

    cudaEvent_t start, end;
    CUDA_SAFE_CALL(cudaEventCreate(&start));
    CUDA_SAFE_CALL(cudaEventCreate(&end));

    double kernel_time_mad_sp = benchmark<total_bench_iterations>([&]() {
        const float seed_f = 1.0f;
        kernel_args[0] = (void*)&seed_f;
        kernel_args[1] = (void*)cbuffer;
        CUDA_SAFE_CALL(cudaEventRecord(start));
        CUDA_SAFE_CALL(cudaLaunchKernel(kernels[kdt_float][krn_idx], grid, block, 0, 0, kernel_args));
        CUDA_SAFE_CALL(cudaEventRecord(end));
        CUDA_SAFE_CALL(cudaEventSynchronize(end));
        float duration;
        CUDA_SAFE_CALL(cudaEventElapsedTime(&duration, start, end));
        return (double)duration;
    });

    double kernel_time_mad_dp = benchmark<total_bench_iterations>([&]() {
        const double seed_d = 1.0;
        kernel_args[0] = (void*)&seed_d;
        kernel_args[1] = (void*)cbuffer;
        CUDA_SAFE_CALL(cudaEventRecord(start));
        CUDA_SAFE_CALL(cudaLaunchKernel(kernels[kdt_double][krn_idx], grid, block, 0, 0, kernel_args));
        CUDA_SAFE_CALL(cudaEventRecord(end));
        CUDA_SAFE_CALL(cudaEventSynchronize(end));
        float duration;
        CUDA_SAFE_CALL(cudaEventElapsedTime(&duration, start, end));
        return (double)duration;
    });

    double kernel_time_mad_hp = benchmark<total_bench_iterations>([&]() {
        if(kernels[kdt_half][krn_idx] == nullptr)
            return 0.0;
        struct { unsigned short x, y; } seed_h = {15360, 15360};
        kernel_args[0] = (void*)&seed_h;
        kernel_args[1] = (void*)cbuffer;
        CUDA_SAFE_CALL(cudaEventRecord(start));
        CUDA_SAFE_CALL(cudaLaunchKernel(kernels[kdt_half][krn_idx], grid, block, 0, 0, kernel_args));
        CUDA_SAFE_CALL(cudaEventRecord(end));
        CUDA_SAFE_CALL(cudaEventSynchronize(end));
        float duration;
        CUDA_SAFE_CALL(cudaEventElapsedTime(&duration, start, end));
        return (double)duration;
    });

    double kernel_time_mad_int = benchmark<total_bench_iterations>([&]() {
        const int seed_i = 1;
        kernel_args[0] = (void*)&seed_i;
        kernel_args[1] = (void*)cbuffer;
        CUDA_SAFE_CALL(cudaEventRecord(start));
        CUDA_SAFE_CALL(cudaLaunchKernel(kernels[kdt_int][krn_idx], grid, block, 0, 0, kernel_args));
        CUDA_SAFE_CALL(cudaEventRecord(end));
        CUDA_SAFE_CALL(cudaEventSynchronize(end));
        float duration;
        CUDA_SAFE_CALL(cudaEventElapsedTime(&duration, start, end));
        return (double)duration;
    });

    CUDA_SAFE_CALL(cudaEventDestroy(start));
    CUDA_SAFE_CALL(cudaEventDestroy(end));

    printf(
        "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
        "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        current_compute_iterations,
        ((double)computations) / ((double)memoryoperations * sizeof(float)),
        kernel_time_mad_sp,
        ((double)computations) / kernel_time_mad_sp * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(double)),
        kernel_time_mad_dp,
        ((double)computations) / kernel_time_mad_dp * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
            (1000. * 1000. * 1000.),
