extern "C" void mixbenchGPU(double* c, long size) {
    printf("Workitem stride:        NDRange\n");
    printf("Buffer allocation:      Device allocated\n");
    printf("Timer:                  CUDA event based\n");

    cudaDeviceProp deviceProp;
    int current_device;
    CUDA_SAFE_CALL(cudaGetDevice(&current_device));
    CUDA_SAFE_CALL(cudaGetDeviceProperties(&deviceProp, current_device));

    bool enable_dp = deviceProp.major >= 1;
    bool enable_hp = deviceProp.major >= 5 || (deviceProp.major == 5 && deviceProp.minor >= 3);

    if (!enable_dp)
        printf(
            "Warning:                Double precision computations are not "
            "supported\n");
    if (!enable_hp)
        printf(
            "Warning:                Half precision computations are not "
            "supported\n");

    CUDA_SAFE_CALL(cudaSetDevice(current_device));

    double* c_buffer;
    CUDA_SAFE_CALL(cudaMalloc(&c_buffer, size * sizeof(double)));

    CUDA_SAFE_CALL(cudaMemset(c_buffer, 0, size * sizeof(double)));

    printf("Loading kernel source file...\n");
    const char* c_kernel_source = ReadFile("mix_kernels.cu");
    printf("Precompilation of kernels... ");

    dim3 block(256, 1, 1);

    show_progress_init(compute_iterations_len);
    cudaKernel_t kernels[kdt_half + 1][compute_iterations_len];
    void* kernel_args[2];

    for (int i = 0; i < compute_iterations_len; i++) {
        show_progress_step(0, '\\');

        kernels[kdt_float][i] = CompileKernel(c_kernel_source, "benchmark_func_float", 
            256, compute_iterations[i], 8, 4, 0, 0);

        show_progress_step(0, '|');

        kernels[kdt_int][i] = CompileKernel(c_kernel_source, "benchmark_func_int",
            256, compute_iterations[i], 8, 4, 0, 0);

        if (enable_dp) {
            show_progress_step(0, '/');

            kernels[kdt_double][i] = CompileKernel(c_kernel_source, "benchmark_func_double",
                256, compute_iterations[i], 8, 4, 0, 0);
        } else
            kernels[kdt_double][i] = nullptr;

        if (enable_hp) {
            show_progress_step(0, '-');

            kernels[kdt_half][i] = CompileKernel(c_kernel_source, "benchmark_func_half",
                256, compute_iterations[i], 8, 4, 0, 0);
        } else
            kernels[kdt_half][i] = nullptr;

        show_progress_step(1, '>');
    }
    show_progress_done();
    free((char*)c_kernel_source);

    dim3 warmup_grid;
    warmup_grid.x = (size / 256) / block.x;
    if(warmup_grid.x < 1) warmup_grid.x = 1;
    warmup_grid.y = 1;
    warmup_grid.z = 1;

    int seed_warmup = 1;
    void* warmup_args[2] = {(void*)&seed_warmup, (void*)c_buffer};

    cudaKernel_t kernel_warmup = CompileKernel(c_kernel_source, "benchmark_func_warmup",
        256, 0, 1, 1, 0, 0);

    runbench_warmup(block, warmup_grid, kernel_warmup, warmup_args, size);

    CUDA_SAFE_CALL(cudaDeviceSynchronize());

    printf(
        "------------------------------------------------------------------------"
        "----- CSV data "
        "------------------------------------------------------------------------"
        "-----\n");
    printf(
        "Experiment ID, Single Precision ops,,,,              Double precision "
        "ops,,,,              Half precision ops,,,,                Integer "
        "operations,,, \n");
    printf(
        "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
        "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
        "Iops/byte, ex.time,   GIOPS, GB/sec\n");

    for (int i = 0; i < compute_iterations_len; i++)
        runbench(compute_iterations, i, block, kernels, kernel_args, c_buffer, size,
                 8, 4);

    printf(
        "------------------------------------------------------------------------"
        "------------------------------------------------------------------------"
        "--------------------\n");

    CUDA_SAFE_CALL(cudaMemcpy(c, c_buffer, size * sizeof(double), cudaMemcpyDeviceToHost));

    for (int i = 0; i < compute_iterations_len; i++) {
        if(kernels[kdt_float][i]) ReleaseKernel(kernels[kdt_float][i]);
        if(kernels[kdt_int][i]) ReleaseKernel(kernels[kdt_int][i]);
        if(kernels[kdt_double][i]) ReleaseKernel(kernels[kdt_double][i]);
        if(kernels[kdt_half][i]) ReleaseKernel(kernels[kdt_half][i]);
    }
    if(kernel_warmup) ReleaseKernel(kernel_warmup);

    CUDA_SAFE_CALL(cudaFree(c_buffer));
}

