// CUDA kernel for benchmarking
template<typename T>
__global__ void benchmark_func_kernel(T seed, T *g_data, 
                                      unsigned int blockSize,
                                      unsigned int elements_per_thread,
                                      unsigned int fusion_degree,
                                      unsigned int compute_iterations,
                                      bool block_strided,
                                      unsigned int num_groups) {
    const unsigned int idx = block_strided ? 
        (blockIdx.x * blockSize * elements_per_thread + threadIdx.x) :
        (blockIdx.x * blockSize + threadIdx.x);
    const unsigned int stride = block_strided ? blockSize : (blockSize * num_groups);
    const unsigned int big_stride = num_groups * blockSize * elements_per_thread;

    T tmps[elements_per_thread];
    for(unsigned int k = 0; k < fusion_degree; k++) {
        for(unsigned int j = 0; j < elements_per_thread; j++) {
            tmps[j] = g_data[idx + j * stride + k * big_stride];

            for(unsigned int i = 0; i < compute_iterations; i++) {
                tmps[j] = tmps[j] * tmps[j] + seed;
            }
        }

        T sum = (T)0;
        for(unsigned int j = 0; j < elements_per_thread; j += 2)
            sum += tmps[j] * tmps[j + 1];

        if(sum == (T)-1) 
            g_data[idx + k * big_stride] = sum;
    }
}

// Timing functions
double get_cuda_event_duration(cudaEvent_t start, cudaEvent_t end) {
    float time_ms;
    cudaEventElapsedTime(&time_ms, start, end);
    return time_ms / 1000.0;
}

// Benchmarking function
void runbench(const int compute_iterations[],
              unsigned int krn_idx,
              cudaStream_t stream,
              double *c_buffer,
              long size,
              size_t workgroupsize,
              unsigned int elements_per_wi,
              unsigned int fusion_degree,
              bool use_os_timer) {
    const long compute_grid_size = size / elements_per_wi / fusion_degree;
    const int current_compute_iterations = compute_iterations[krn_idx];
    const long long computations =
        (elements_per_wi * (long long)compute_grid_size +
         (2 * elements_per_wi * current_compute_iterations) *
             (long long)compute_grid_size) *
        fusion_degree;
    const long long memoryoperations = size;

    dim3 block(workgroupsize);
    dim3 grid(compute_grid_size / workgroupsize);

    constexpr auto total_bench_iterations = 3;

    double kernel_time_mad_sp = 0;
    double kernel_time_mad_dp = 0;
    double kernel_time_mad_hp = 0;
    double kernel_time_mad_int = 0;

    // Benchmark float
    for(int iter = 0; iter < total_bench_iterations; iter++) {
        cudaEvent_t start, end;
        cudaEventCreate(&start);
        cudaEventCreate(&end);
        cudaEventRecord(start, stream);

        benchmark_func_kernel<float>(1.0f, (float*)c_buffer, block.x, elements_per_wi, fusion_degree, current_compute_iterations, false, grid.x);

        cudaEventRecord(end, stream);
        cudaEventSynchronize(end);
        kernel_time_mad_sp += get_cuda_event_duration(start, end);
        cudaEventDestroy(start);
        cudaEventDestroy(end);
    }
    kernel_time_mad_sp /= total_bench_iterations;

    // Benchmark double
    for(int iter = 0; iter < total_bench_iterations; iter++) {
        cudaEvent_t start, end;
        cudaEventCreate(&start);
        cudaEventCreate(&end);
        cudaEventRecord(start, stream);

        benchmark_func_kernel<double>(1.0, c_buffer, block.x, elements_per_wi, fusion_degree, current_compute_iterations, false, grid.x);

        cudaEventRecord(end, stream);
        cudaEventSynchronize(end);
        kernel_time_mad_dp += get_cuda_event_duration(start, end);
        cudaEventDestroy(start);
        cudaEventDestroy(end);
    }
    kernel_time_mad_dp /= total_bench_iterations;

    // Benchmark half (using unsigned short)
    for(int iter = 0; iter < total_bench_iterations; iter++) {
        cudaEvent_t start, end;
        cudaEventCreate(&start);
        cudaEventCreate(&end);
        cudaEventRecord(start, stream);

        benchmark_func_kernel<unsigned short>(15360, (unsigned short*)c_buffer, block.x, elements_per_wi, fusion_degree, current_compute_iterations, false, grid.x);

        cudaEventRecord(end, stream);
        cudaEventSynchronize(end);
        kernel_time_mad_hp += get_cuda_event_duration(start, end);
        cudaEventDestroy(start);
        cudaEventDestroy(end);
    }
    kernel_time_mad_hp /= total_bench_iterations;

    // Benchmark int
    for(int iter = 0; iter < total_bench_iterations; iter++) {
        cudaEvent_t start, end;
        cudaEventCreate(&start);
        cudaEventCreate(&end);
        cudaEventRecord(start, stream);

        benchmark_func_kernel<int>(1, (int*)c_buffer, block.x, elements_per_wi, fusion_degree, current_compute_iterations, false, grid.x);

        cudaEventRecord(end, stream);
        cudaEventSynchronize(end);
        kernel_time_mad_int += get_cuda_event_duration(start, end);
        cudaEventDestroy(start);
        cudaEventDestroy(end);
    }
    kernel_time_mad_int /= total_bench_iterations;

    printf("         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
           "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
           current_compute_iterations,
           ((double)computations) / ((double)memoryoperations * sizeof(float)),
           kernel_time_mad_sp,
           ((double)computations) / kernel_time_mad_sp * 1000.0 /
               (double)(1000 * 1000 * 1000),
           ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000.0 /
               (1000.0 * 1000.0 * 1000.0),
           ((double)computations) / ((double)memoryoperations * sizeof(double)),
           kernel_time_mad_dp,
           ((double)computations) / kernel_time_mad_dp * 1000.0 /
               (double)(1000 * 1000 * 1000),
           ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000.0 /
               (1000.0 * 1000.0 * 1000.),
           ((double)2 * computations) /
               ((double)memoryoperations * sizeof(unsigned short)),
           kernel_time_mad_hp,
           ((double)2 * computations) / kernel_time_mad_hp * 1000.0 /
               (double)(1000 * 1000 * 1000),
           ((double)memoryoperations * sizeof(unsigned short)) / kernel_time_mad_hp *
               1000.0 / (1000.0 * 1000.0 * 1000.),
           ((double)computations) / ((double)memoryoperations * sizeof(int)),
           kernel_time_mad_int,
           ((double)computations) / kernel_time_mad_int * 1000.0 /
               (double)(1000 * 1000 * 1000),
           ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000.0 /
               (1000.0 * 1000.0 * 1000.));
}

extern "C" void mixbenchGPU(double* c, long size) {
