    printf("Timer:                  %s\n", use_os_timer ? "OS based" : "CUDA event based");

    double *c_buffer;
    cudaMalloc(&c_buffer, size * sizeof(double));

    cudaMemset(c_buffer, 0, size * sizeof(double));

    dim3 block(workgroupsize);
    dim3 grid(size / 256 / workgroupsize);

    // Warmup
    benchmark_func_kernel<double>(1.0, c_buffer, block.x, 1, 1, 0, false, grid.x);

    cudaDeviceSynchronize();

    printf("------------------------------------------------------------------------"
